const express = require('express');
const app = express();
const pg = require('pg');

// Connect to PostgreSQL using the postgres superuser account
const client = new pg.Client({
  user: 'postgres',
  host: 'localhost',
  database: 'mydatabase',
  password: 'mypassword'
});
client.connect();

// Implement CRUD operations for multiple tables
app.get('/users', (req, res) => {
  const query = 'SELECT * FROM users';
  client.query(query, (err, result) => {
    if (err) {
      console.error(err);
      return res.status(500).send('Error retrieving users');
    }
    res.json(result.rows);
  });
});

app.post('/users', (req, res) => {
  const query = 'INSERT INTO users (name, email) VALUES ($1, $2)';
  client.query(query, [req.body.name, req.body.email], (err, result) => {
    if (err) {
      console.error(err);
      return res.status(500).send('Error creating user');
    }
    res.json({ message: 'User created successfully' });
  });
});

app.get('/users/:id', (req, res) => {
  const query = 'SELECT * FROM users WHERE id = $1';
  client.query(query, [req.params.id], (err, result) => {
    if (err) {
      console.error(err);
      return res.status(500).send('Error retrieving user');
    }
    if (!result.rows.length) {
      return res.status(404).send('User not found');
    }
    res.json(result.rows[0]);
  });
});

app.put('/users/:id', (req, res) => {
  const query = 'UPDATE users SET name = $1, email = $2 WHERE id = $3';
  client.query(query, [req.body.name, req.body.email, req.params.id], (err, result) => {
    if (err) {
      console.error(err);
      return res.status(500).send('Error updating user');
    }
    res.json({ message: 'User updated successfully' });
  });
});

app.delete('/users/:id', (req, res) => {
  const query = 'DELETE FROM users WHERE id = $1';
  client.query(query, [req.params.id], (err, result) => {
    if (err) {
      console.error(err);
      return res.status(500).send('Error deleting user');
    }
    res.json({ message: 'User deleted successfully' });
  });
});